// src/styles/map.scss
var map_default = ".geo-map-wrapper {\n  margin: 1rem 0;\n}\n\n.geo-map {\n  height: 480px;\n  width: 100%;\n  border-radius: 8px;\n  overflow: hidden;\n  z-index: 0;\n}\n\n.geo-map-empty {\n  padding: 1rem;\n  border: 1px dashed var(--lightgray);\n  border-radius: 8px;\n  color: var(--gray);\n  font-size: 0.9rem;\n}\n\n.geo-pin {\n  width: 18px;\n  height: 18px;\n  border-radius: 50%;\n  border: 2px solid #fff;\n  box-shadow: 0 0 3px rgba(0, 0, 0, 0.5);\n}\n\n.geo-pin-emoji {\n  width: auto;\n  height: auto;\n  border: none;\n  border-radius: 0;\n  box-shadow: none;\n  background: transparent !important;\n  font-size: 20px;\n  line-height: 1;\n  text-shadow: 0 0 2px rgba(0, 0, 0, 0.35);\n}\n\n.maplibregl-popup-content {\n  background: var(--light);\n  color: var(--darkgray);\n  border-radius: 6px;\n  box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3);\n  padding: 0.4rem 0.7rem;\n}\n\n.maplibregl-popup-content a {\n  color: var(--secondary);\n}\n\n.maplibregl-popup-tip {\n  border-top-color: var(--light);\n  border-bottom-color: var(--light);\n}\n\n.maplibregl-ctrl-attrib {\n  background: transparent !important;\n}";

